   167→// ============================================================================
   168→// Saddle - Return context needed to saddle up on a Heat
   169→// ============================================================================
   170→
   171→/// Arguments for saddle command
   172→#[derive(Debug)]
   173→pub struct jjrq_SaddleArgs {
   174→    pub file: std::path::PathBuf,
   175→    pub firemark: Firemark,
   176→}
   177→
   178→/// Run the saddle command - return Heat context
   179→pub fn jjrq_run_saddle(args: jjrq_SaddleArgs) -> i32 {
   180→    let gallops = match Gallops::jjrg_load(&args.file) {
   181→        Ok(g) => g,
   182→        Err(e) => {
   183→            eprintln!("jjx_saddle: error: {}", e);
   184→            return 1;
   185→        }
   186→    };
   187→
   188→    let heat_key = args.firemark.jjrf_display();
   189→    let heat = match gallops.heats.get(&heat_key) {
   190→        Some(h) => h,
   191→        None => {
   192→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
   193→            return 1;
   194→        }
   195→    };
   196→
   197→    // Check if heat is stabled (cannot saddle stabled heat)
   198→    if heat.status == HeatStatus::Stabled {
   199→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
   200→        return 1;
   201→    }
   202→
   203→    // Read paddock file content
   204→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   205→        Ok(content) => content,
   206→        Err(e) => {
   207→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   208→            return 1;
   209→        }
   210→    };
   211→
   212→    // Get recent steeplechase entries
   213→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   214→        firemark: args.firemark.jjrf_as_str().to_string(),
   215→        limit: 10,
   216→    }).unwrap_or_default();
   217→
   218→    // Find first actionable pace (rough or bridled)
   219→    let mut pace_coronet: Option<String> = None;
   220→    let mut pace_silks: Option<String> = None;
   221→    let mut pace_state: Option<String> = None;
   222→    let mut spec: Option<String> = None;
   223→    let mut direction: Option<String> = None;
   224→
   225→    for coronet_key in &heat.order {
   226→        if let Some(pace) = heat.paces.get(coronet_key) {
   227→            if let Some(tack) = pace.tacks.first() {
   228→                match tack.state {
   229→                    PaceState::Rough | PaceState::Bridled => {
   230→                        pace_coronet = Some(coronet_key.clone());
   231→                        pace_silks = Some(tack.silks.clone());
   232→                        pace_state = Some(match tack.state {
   233→                            PaceState::Rough => "rough".to_string(),
   234→                            PaceState::Bridled => "bridled".to_string(),
   235→                            _ => unreachable!(),
   236→                        });
   237→                        spec = Some(tack.text.clone());
   238→                        if tack.state == PaceState::Bridled {
   239→                            direction = tack.direction.clone();
   240→                        }
   241→                        break;
   242→                    }
   243→                    _ => continue,
   244→                }
   245→            }
   246→        }
   247→    }
   248→
   249→    // Determine heat status string
   250→    let status_str = match heat.status {
   251→        HeatStatus::Racing => "racing",
   252→        HeatStatus::Stabled => "stabled",
   253→        HeatStatus::Retired => "retired",
   254→    };
   255→
   256→    // Output plain text format
   257→    println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   258→    println!("Paddock: {}", heat.paddock_file);
   259→    println!();
   260→    println!("Paddock-content:");
   261→    for line in paddock_content.lines() {
   262→        println!("  {}", line);
   263→    }
   264→    println!();
   265→
   266→    if let Some(coronet) = pace_coronet {
   267→        if let Some(silks) = pace_silks {
   268→            if let Some(state) = pace_state {
   269→                println!("Next: {} ({}) [{}]", silks, coronet, state);
   270→                println!();
   271→                if let Some(spec_text) = spec {
   272→                    println!("Spec:");
   273→                    for line in spec_text.lines() {
   274→                        println!("  {}", line);
   275→                    }
   276→                    println!();
   277→                }
   278→                if let Some(dir_text) = direction {
   279→                    println!("Direction:");
   280→                    for line in dir_text.lines() {
   281→                        println!("  {}", line);
   282→                    }
   283→                    println!();
   284→                }
   285→            }
   286→        }
   287→    }
   288→
   289→    // Output recent work table
   290→    // Filter entries to only show action codes 'n' (notch), 'A' (approach), 'd' (discussion)
   291→    let filtered_work: Vec<_> = recent_work.iter().filter(|entry| {
   292→        if let Some(ref action) = entry.action {
   293→            action == "n" || action == "A" || action == "d"
   294→        } else {
   295→            false
   296→        }
   297→    }).collect();
   298→
   299→    if !filtered_work.is_empty() {
   300→        println!("Recent-work:");
   301→
   302→        let mut table = jjrp_Table::jjrp_new(vec![
   303→            jjrp_Column::new("Commit", jjrp_Align::Left),
   304→            jjrp_Column::new("Identity", jjrp_Align::Left),
   305→            jjrp_Column::new("Subject", jjrp_Align::Left),
   306→        ]);
   307→
   308→        // Measure all rows to compute column widths
   309→        for entry in &filtered_work {
   310→            let identity_str = if let Some(ref coronet) = entry.coronet {
   311→                coronet.clone()
   312→            } else {
   313→                heat_key.clone()
   314→            };
   315→            table.jjrp_measure(&[
   316→                &entry.commit,
   317→                &identity_str,
   318→                &entry.subject,
   319→            ]);
   320→        }
   321→
   322→        // Print header and separator
   323→        table.jjrp_print_header();
   324→        table.jjrp_print_separator();
   325→
   326→        // Print data rows
   327→        for entry in &filtered_work {
   328→            let identity_str = if let Some(ref coronet) = entry.coronet {
   329→                coronet.clone()
   330→            } else {
   331→                heat_key.clone()
   332→            };
   333→            table.jjrp_print_row(&[
   334→                &entry.commit,
   335→                &identity_str,
   336→                &entry.subject,
   337→            ]);
   338→        }
   339→    }
   340→
   341→    // Check if session probe is needed (gap > 1 hour or no commits)
   342→    let last_timestamp = recent_work.first().map(|e| e.timestamp.as_str());
   343→    if crate::jjrc_core::jjrc_needs_session_probe(last_timestamp) {
   344→        println!();
   345→        println!("Needs-session-probe: true");
   346→    }
   347→
   348→    0
   349→}
   350→
   351→// ============================================================================
   352→// Parade - Display comprehensive Heat status for project review
   353→// ============================================================================
   354→
   355→/// Arguments for parade command
   356→#[derive(Debug)]
   357→pub struct jjrq_ParadeArgs {
   358→    pub file: std::path::PathBuf,
   359→    pub target: String,
   360→    pub full: bool,
   361→    pub remaining: bool,
   362→}
   363→
   364→/// Run the parade command - display comprehensive Heat status
   365→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   366→    let gallops = match Gallops::jjrg_load(&args.file) {
   367→        Ok(g) => g,
   368→        Err(e) => {
   369→            eprintln!("jjx_parade: error: {}", e);
   370→            return 1;
   371→        }
   372→    };
   373→
   374→    // Determine target type by length
   375→    let target_str = args.target.strip_prefix('₢').or_else(|| args.target.strip_prefix('₣')).unwrap_or(&args.target);
   376→
   377→    if target_str.len() == 5 {
   378→        // Coronet - pace view
   379→        let coronet = match Coronet::jjrf_parse(&args.target) {
   380→            Ok(c) => c,
   381→            Err(e) => {
   382→                eprintln!("jjx_parade: error: {}", e);
   383→                return 1;
   384→            }
   385→        };
   386→
   387→        // Extract parent firemark
   388→        let firemark = coronet.jjrf_parent_firemark();
   389→        let heat_key = firemark.jjrf_display();
   390→        let heat = match gallops.heats.get(&heat_key) {
   391→            Some(h) => h,
   392→            None => {
   393→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   394→                return 1;
   395→            }
   396→        };
   397→
   398→        // Find pace
   399→        let coronet_key = coronet.jjrf_display();
   400→        let pace = match heat.paces.get(&coronet_key) {
   401→            Some(p) => p,
   402→            None => {
   403→                eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
   404→                return 1;
   405→            }
   406→        };
   407→
   408→        // Display tack history - iterate in reverse order (oldest first)
   409→        if !pace.tacks.is_empty() {
   410→            // Print header with current state from tacks[0]
   411→            let current_tack = &pace.tacks[0];
   412→            println!("Pace: {} ({})", current_tack.silks, coronet_key);
   413→            println!("Heat: {}", heat_key);
   414→            println!();
   415→
   416→            // Iterate tacks in reverse order (oldest first)
   417→            for (index, tack) in pace.tacks.iter().rev().enumerate() {
   418→                let state_str = zjjrq_pace_state_str(&tack.state);
   419→                let commit_str = if tack.commit == "0000000" {
   420→                    "(no commit)".to_string()
   421→                } else {
   422→                    tack.commit.clone()
   423→                };
   424→
   425→                println!("[{}] {} ({})", index, state_str, commit_str);
   426→                println!("    Silks: {}", tack.silks);
   427→                if let Some(ref direction) = tack.direction {
   428→                    println!("    Direction: {}", direction);
   429→                }
   430→                println!();
   431→                // Indent spec text
   432→                for line in tack.text.lines() {
   433→                    println!("    {}", line);
   434→                }
   435→                println!();
   436→            }
   437→        }
   438→    } else if target_str.len() == 2 {
   439→        // Firemark - heat view
   440→        let firemark = match Firemark::jjrf_parse(&args.target) {
   441→            Ok(fm) => fm,
   442→            Err(e) => {
   443→                eprintln!("jjx_parade: error: {}", e);
   444→                return 1;
   445→            }
   446→        };
   447→
   448→        let heat_key = firemark.jjrf_display();
   449→        let heat = match gallops.heats.get(&heat_key) {
   450→            Some(h) => h,
   451→            None => {
   452→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   453→                return 1;
   454→            }
   455→        };
   456→
   457→        if args.full {
   458→            // Full view: paddock + all specs
   459→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   460→                Ok(content) => content,
   461→                Err(e) => {
   462→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   463→                    return 1;
   464→                }
   465→            };
   466→
   467→            let status_str = match heat.status {
   468→                HeatStatus::Racing => "racing",
   469→                HeatStatus::Stabled => "stabled",
   470→                HeatStatus::Retired => "retired",
   471→            };
   472→
   473→            println!("Heat: {} ({})", heat.silks, heat_key);
   474→            println!("Status: {}", status_str);
   475→            println!("Created: {}", heat.creation_time);
   476→            println!();
   477→            println!("## Paddock");
   478→            println!();
   479→            println!("{}", paddock_content);
   480→            println!();
   481→            println!("## Paces");
   482→            println!();
   483→
   484→            for coronet_key in &heat.order {
   485→                if let Some(pace) = heat.paces.get(coronet_key) {
   486→                    if let Some(tack) = pace.tacks.first() {
   487→                        // Skip complete/abandoned if --remaining
   488→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   489→                            continue;
   490→                        }
   491→                        let state_str = zjjrq_pace_state_str(&tack.state);
   492→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   493→                        println!();
   494→                        println!("{}", tack.text);
   495→                        if let Some(ref direction) = tack.direction {
   496→                            println!();
   497→                            println!("**Direction:** {}", direction);
   498→                        }
   499→                        println!();
   500→                    }
   501→                }
   502→            }
   503→        } else {
   504→            // List view: numbered paces
   505→            // If --remaining, output markdown format
   506→            if args.remaining {
   507→                let mut complete_count = 0;
   508→                let mut abandoned_count = 0;
   509→                let mut rough_count = 0;
   510→                let mut bridled_count = 0;
   511→                let mut remaining_paces: Vec<(&String, &crate::jjrg_gallops::jjrg_Pace)> = Vec::new();
   512→                let mut first_remaining_pace: Option<(&String, &crate::jjrg_gallops::jjrg_Pace)> = None;
   513→
   514→                for coronet_key in &heat.order {
   515→                    if let Some(pace) = heat.paces.get(coronet_key) {
   516→                        if let Some(tack) = pace.tacks.first() {
   517→                            match tack.state {
   518→                                PaceState::Complete => complete_count += 1,
   519→                                PaceState::Abandoned => abandoned_count += 1,
   520→                                PaceState::Rough => {
   521→                                    rough_count += 1;
   522→                                    remaining_paces.push((coronet_key, pace));
   523→                                    if first_remaining_pace.is_none() {
   524→                                        first_remaining_pace = Some((coronet_key, pace));
   525→                                    }
   526→                                }
   527→                                PaceState::Bridled => {
   528→                                    bridled_count += 1;
   529→                                    remaining_paces.push((coronet_key, pace));
   530→                                    if first_remaining_pace.is_none() {
   531→                                        first_remaining_pace = Some((coronet_key, pace));
   532→                                    }
   533→                                }
   534→                            }
   535→                        }
   536→                    }
   537→                }
   538→
   539→                let status_str = match heat.status {
   540→                    HeatStatus::Racing => "racing",
   541→                    HeatStatus::Stabled => "stabled",
   542→                    HeatStatus::Retired => "retired",
   543→                };
   544→
   545→                let remaining_count = rough_count + bridled_count;
   546→
   547→                // Header line with heat info
   548→                println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   549→                println!("Progress: {} complete | {} abandoned | {} remaining ({} rough, {} bridled)",
   550→                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
   551→                println!();
   552→
   553→                // Table with remaining paces
   554→                if !remaining_paces.is_empty() {
   555→                    // Set up table with column definitions
   556→                    let mut table = jjrp_Table::jjrp_new(vec![
   557→                        jjrp_Column::new("No", jjrp_Align::Right),
   558→                        jjrp_Column::new("State", jjrp_Align::Left),
   559→                        jjrp_Column::new("Pace", jjrp_Align::Left),
   560→                        jjrp_Column::new("₢Coronet", jjrp_Align::Left),
   561→                    ]);
   562→
   563→                    // Measure all rows to compute column widths
   564→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
   565→                        if let Some(tack) = pace.tacks.first() {
   566→                            let state_str = zjjrq_pace_state_str(&tack.state);
   567→                            table.jjrp_measure(&[
   568→                                &(idx + 1).to_string(),
   569→                                state_str,
   570→                                &tack.silks,
   571→                                coronet_key,
   572→                            ]);
   573→                        }
   574→                    }
   575→
   576→                    // Print header and separator
   577→                    table.jjrp_print_header();
   578→                    table.jjrp_print_separator();
   579→
   580→                    // Print data rows
   581→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
   582→                        if let Some(tack) = pace.tacks.first() {
   583→                            let state_str = zjjrq_pace_state_str(&tack.state);
   584→                            table.jjrp_print_row(&[
   585→                                &(idx + 1).to_string(),
   586→                                state_str,
   587→                                &tack.silks,
   588→                                coronet_key,
   589→                            ]);
   590→                        }
   591→                    }
   592→                    println!();
   593→                }
   594→
   595→                // Next up callout
   596→                if let Some((coronet_key, pace)) = first_remaining_pace {
   597→                    if let Some(tack) = pace.tacks.first() {
   598→                        let state_str = zjjrq_pace_state_str(&tack.state);
   599→                        println!("Next: {} ({}) [{}]", tack.silks, coronet_key, state_str);
   600→                    }
   601→                }
   602→            } else {
   603→                // Column-justified list view (all paces)
   604→                // Set up table with column definitions
   605→                let mut table = jjrp_Table::jjrp_new(vec![
   606→                    jjrp_Column::new("No", jjrp_Align::Right),
   607→                    jjrp_Column::new("State", jjrp_Align::Left),
   608→                    jjrp_Column::new("Pace", jjrp_Align::Left),
   609→                    jjrp_Column::new("₢Coronet", jjrp_Align::Left),
   610→                ]);
   611→
   612→                // Measure all rows to compute column widths
   613→                let mut num = 0;
   614→                for coronet_key in &heat.order {
   615→                    if let Some(pace) = heat.paces.get(coronet_key) {
   616→                        if let Some(tack) = pace.tacks.first() {
   617→                            num += 1;
   618→                            let state_str = zjjrq_pace_state_str(&tack.state);
   619→                            table.jjrp_measure(&[
   620→                                &num.to_string(),
   621→                                state_str,
   622→                                &tack.silks,
   623→                                coronet_key,
   624→                            ]);
   625→                        }
   626→                    }
   627→                }
   628→
   629→                // Print header and separator
   630→                table.jjrp_print_header();
   631→                table.jjrp_print_separator();
   632→
   633→                // Print data rows
   634→                let mut num = 0;
   635→                for coronet_key in &heat.order {
   636→                    if let Some(pace) = heat.paces.get(coronet_key) {
   637→                        if let Some(tack) = pace.tacks.first() {
   638→                            num += 1;
   639→                            let state_str = zjjrq_pace_state_str(&tack.state);
   640→                            table.jjrp_print_row(&[
   641→                                &num.to_string(),
   642→                                state_str,
   643→                                &tack.silks,
   644→                                coronet_key,
   645→                            ]);
   646→                        }
   647→                    }
   648→                }
   649→            }
   650→        }
   651→    } else {
   652→        eprintln!("jjx_parade: error: target must be Firemark (2 chars) or Coronet (5 chars), got {} chars", target_str.len());
   653→        return 1;
   654→    }
   655→
   656→    0
   657→}
